// Function to lookup and return fallback
function getTopicSpecificFallback(topic) {
  let lowerTopic = (topic || '').toLowerCase().trim();
  for (let key in MASSIVE_FALLBACK_DB) {
    if (lowerTopic.includes(key)) {
      return MASSIVE_FALLBACK_DB[key];
    }
  }
  return MASSIVE_FALLBACK_DB['blockchain']; // Default generic
}
